from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an artist (or related entity) into a single
    fluent sentence.  Simple template rules are applied for the most common
    predicates; unknown predicates fall back to a generic “subject predicate object”
    phrasing.  All parts are joined with semicolons to keep the sentence readable.
    """
    if not triples:
        return ""

    parts: list[str] = []

    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # Specific templates for well‑known predicates
        if p == "birthDate":
            parts.append(f"{s} was born on {o}")
        elif p == "birthYear":
            parts.append(f"{s} was born in {o}")
        elif p == "birthPlace":
            parts.append(f"{s} was born in {o}")
        elif p == "deathDate":
            parts.append(f"{s} died on {o}")
        elif p == "deathPlace":
            parts.append(f"{s} died in {o}")
        elif p == "origin":
            parts.append(f"{s} is from {o}")
        elif p == "genre":
            parts.append(f"{s} performs {o}")
        elif p == "instrument":
            parts.append(f"{s} plays the {o}")
        elif p == "occupation":
            parts.append(f"{s} works as {o}")
        elif p == "associatedBand/associatedMusicalArtist":
            parts.append(f"{s} is associated with {o}")
        elif p == "recordLabel":
            parts.append(f"{s} is signed to {o}")
        elif p == "activeYearsStartYear":
            parts.append(f"{s} started their career in {o}")
        elif p == "activeYearsEndYear":
            parts.append(f"{s} ended their career in {o}")
        elif p == "nationality":
            parts.append(f"{s} is {o}")
        elif p == "capital":
            parts.append(f"The capital of {s} is {o}")
        else:
            # Generic fallback
            parts.append(f"{s} {p} {o}")

    # Combine parts into one coherent sentence
    sentence = "; ".join(parts) + "."
    return sentence

# EVOLVE-BLOCK-END

